# apply_v8_2_approval_gate_patch.py
# 用法：放到 ugai_agent_langgraph_v0 根目录运行：
# python apply_v8_2_approval_gate_patch.py

from pathlib import Path
import json
import py_compile
import textwrap
import base64
import zlib

DATA = ""

def load_files():
    raw = zlib.decompress(base64.b64decode(DATA.encode("ascii"))).decode("utf-8")
    return json.loads(raw)

def write_clean(path, content):
    path.parent.mkdir(parents=True, exist_ok=True)
    clean = textwrap.dedent(content).lstrip()
    path.write_text(clean, encoding="utf-8")

def main():
    root = Path.cwd()

    if not (root / "config.json").exists():
        raise FileNotFoundError("找不到 config.json。请把脚本放到 ugai_agent_langgraph_v0 根目录运行。")

    files = load_files()

    for rel, content in files.items():
        path = root / rel
        write_clean(path, content)
        print("[OK] 写入", rel)

    config_path = root / "config.json"
    cfg = json.loads(config_path.read_text(encoding="utf-8"))

    tool = cfg.setdefault("tool_bus", {})
    tool["enabled"] = True
    tool["registry_file"] = tool.get("registry_file", "memory_runtime/tool_registry.json")
    tool["runtime_file"] = tool.get("runtime_file", "memory_runtime/tool_calls.json")
    tool["prompt_tool_call_limit"] = int(tool.get("prompt_tool_call_limit", 5))
    tool["auto_execute"] = False
    tool["approval_required"] = True

    cfg.setdefault("task_registry", {}).setdefault("task_file", "memory_runtime/task_registry.json")
    cfg.setdefault("event_model", {}).setdefault("runtime_file", "memory_runtime/event_runtime.json")
    cfg.setdefault("event_log", {}).setdefault("event_file", "memory_runtime/event_log.jsonl")
    cfg.setdefault("fact_memory", {}).setdefault("fact_file", "memory_runtime/fact_memory.json")
    cfg.setdefault("reflection", {}).setdefault("reflection_file", "memory_runtime/reflection_memory.json")

    config_path.write_text(json.dumps(cfg, ensure_ascii=False, indent=2), encoding="utf-8")
    print("[OK] 更新 config.json tool_bus.approval_required")

    for rel in files:
        py_compile.compile(str(root / rel), doraise=True)
        print("[OK] 语法检查", rel)

    print("")
    print("UGAI Agent v8.2 Approval Gate 升级完成。")
    print("")
    print("重启：python main_qq.py")
    print("")
    print("测试：")
    print("1. /tool_policy")
    print("2. /tool_request task_registry {\"action\":\"list\"}")
    print("3. /tool_status")
    print("4. /tool_approve 1")
    print("5. /tool_status")
    print("6. /tool_done 1 已手动处理")
    print("")
    print("注意：v8.2 只做审批门，不会自动执行工具。")

if __name__ == "__main__":
    main()
